// Generic Firestore writer. Body shapes:
//   { collection, action: "create", id?, fields }
//   { collection, action: "bulk_create", items: [ {...fields per doc, optional id} ] }
//   { collection, action: "update", id, fields }          // partial merge
//   { collection, action: "bulk_update", items: [ { id, fields } ] }
// One Firestore REST `:batchWrite` call handles the whole request (cap 500
// writes/request — Firestore's own limit, not this workflow's). Reuses the
// same field-value encoder (`fv`) and the same Firebase_SDK_do_or_wait service
// account pattern already proven working in workflow 19 (Roster Sync).

const PROJECT = 'do-or-wait';
const body = $json.body || {};
const { collection, action } = body;
if (!collection) throw new Error('Missing body.collection');
if (!action) throw new Error('Missing body.action');

function genId(prefix) { return prefix + Date.now().toString() + Math.floor(Math.random() * 100000); }

function fv(v) {
  if (v === null || v === undefined) return { nullValue: null };
  if (typeof v === 'number') return Number.isInteger(v) ? { integerValue: String(v) } : { doubleValue: v };
  if (typeof v === 'boolean') return { booleanValue: v };
  if (Array.isArray(v)) return { arrayValue: { values: v.map(fv) } };
  if (typeof v === 'object') { const fields = {}; for (const k in v) fields[k] = fv(v[k]); return { mapValue: { fields } }; }
  return { stringValue: String(v) };
}

function docName(coll, id) { return `projects/${PROJECT}/databases/(default)/documents/${coll}/${id}`; }

function buildWrite(coll, id, fields, partial) {
  const write = { update: { name: docName(coll, id), fields: Object.fromEntries(Object.entries(fields).map(([k, v]) => [k, fv(v)])) } };
  if (partial) write.updateMask = { fieldPaths: Object.keys(fields) };
  return write;
}

let writes = [], ids = [];
if (action === 'create') {
  const id = body.id || genId(collection.slice(0, 2));
  writes.push(buildWrite(collection, id, body.fields || {}, false));
  ids.push(id);
} else if (action === 'bulk_create') {
  for (const item of (body.items || [])) {
    const id = item.id || genId(collection.slice(0, 2));
    const fields = { ...item }; delete fields.id;
    writes.push(buildWrite(collection, id, fields, false));
    ids.push(id);
  }
} else if (action === 'update') {
  if (!body.id) throw new Error('update requires body.id');
  writes.push(buildWrite(collection, body.id, body.fields || {}, true));
  ids.push(body.id);
} else if (action === 'bulk_update') {
  for (const item of (body.items || [])) {
    if (!item.id) throw new Error('bulk_update item missing id');
    // Items are shaped { id, fields: {...} } (same convention as the single
    // "update" action). Unwrap item.fields — do NOT spread the whole item,
    // that leaves a literal top-level "fields" key on the doc instead of
    // merging its contents (bug found + fixed 2026-07-09).
    const fields = item.fields || {};
    writes.push(buildWrite(collection, item.id, fields, true));
    ids.push(item.id);
  }
} else {
  throw new Error(`Unsupported action "${action}". Supported: create, bulk_create, update, bulk_update.`);
}
if (!writes.length) throw new Error('No writes produced (empty items?).');
if (writes.length > 500) throw new Error(`${writes.length} writes exceeds Firestore batchWrite's 500-per-request cap — split the request into batches of 500 or fewer and call the webhook multiple times.`);

return [{ json: {
  requestUrl: `https://firestore.googleapis.com/v1/projects/${PROJECT}/databases/(default)/documents:batchWrite`,
  requestBody: { writes },
  collection, action, ids, count: ids.length,
} }];
